class Solution:
    def smallestNumber(self, pattern: str) -> str:
        n = len(pattern)
        num = list(range(1, n + 2))
        for i in range(n):
            if pattern[i] == 'D':
                j = i
                while j >= 0 and pattern[j] == 'D':
                    j -= 1
                num[j + 1:i + 2] = num[j + 1:i + 2][::-1]
        return ''.join(map(str, num))

